import type { JSX } from "react";
import { fetchCategoryTree } from "@/app/(main)/courses/new/categories.data";
import { CourseCreateForm } from "@/app/(main)/courses/new/_components/course-create-form.client";

export async function CourseCreateContainer(): Promise<JSX.Element> {
  const categoryTree = await fetchCategoryTree();
  return <CourseCreateForm categoryTree={categoryTree} />;
}

