250	// 12 個の generic を持つ TanStack Form の戻り値型。子コンポーネントへ渡すための alias
251	// eslint-disable-next-line @typescript-eslint/no-explicit-any
252	type Form = ReactFormExtendedApi<CourseBasicFormValues, any, any, any, any, any, any, any, any, any, any, any>;
