254	function CategoryFields({
255	  form,
256	  tree,
257	  disabled,
258	}: {
259	  form: Form;
260	  tree: CategoryNode[];
261	  disabled: boolean;
262	}): JSX.Element {
263	  // 選択肢が 1 件しかない場合は自動選択して下位もチェーンする
264	  const cascadeFromLevel1 = (level1: string): void => {
265	    const level2Options = findLevel1(tree, level1)?.children ?? [];
266	    const level2 = level2Options.length === 1 ? level2Options[0]!.slug : "";
267	    form.setFieldValue("categoryLevel2", level2);
268	    cascadeFromLevel2(level1, level2);
269	  };
270	  const cascadeFromLevel2 = (level1: string, level2: string): void => {
271	    const level3Options =
272	      level2 === ""
273	        ? []
274	        : (findLevel2(tree, level1, level2)?.children ?? []);
275	    const level3 = level3Options.length === 1 ? level3Options[0]!.slug : "";
276	    form.setFieldValue("categoryLevel3", level3);
277	  };
278	
279	  return (
280	    <form.Subscribe
281	      selector={(state) =>
282	        [
283	          state.values.categoryLevel1,
284	          state.values.categoryLevel2,
285	        ] as const
286	      }
287	    >
288	      {([level1Value, level2Value]) => {
289	        const level2Options = findLevel1(tree, level1Value)?.children ?? [];
290	        const level3Options =
291	          findLevel2(tree, level1Value, level2Value)?.children ?? [];
292	        return (
293	          <div className="grid gap-4">
294	            <div className="grid gap-1">
295	              <span className="text-sm font-bold">
296	                カテゴリ
297	                <RequiredOptionalBadge required />
298	              </span>
299	              <p className="text-xs text-muted-foreground">
300	                大分類から順に選択します。
301	              </p>
302	            </div>
303	            <div className="grid gap-4 md:grid-cols-3">
304	              <form.Field name="categoryLevel1">
305	                {(field) => {
306	                  const showError =
307	                    field.state.meta.isBlurred && !field.state.meta.isValid;
308	                  return (
309	                    <Field data-invalid={showError}>
310	                      <FieldLabel htmlFor={field.name}>大分類</FieldLabel>
311	                      <select
312	                        id={field.name}
313	                        name={field.name}
314	                        aria-invalid={showError}
315	                        value={field.state.value}
316	                        onChange={(event) => {
317	                          const next = event.target.value;
318	                          field.handleChange(next);
319	                          cascadeFromLevel1(next);
320	                        }}
321	                        onBlur={field.handleBlur}
322	                        disabled={disabled}
323	                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs"
324	                      >
325	                        <option value="">選択してください</option>
326	                        {tree.map((node) => (
327	                          <option key={node.slug} value={node.slug}>
328	                            {node.name}
329	                          </option>
330	                        ))}
331	                      </select>
332	                      <FieldError
333	                        errors={showError ? field.state.meta.errors : []}
334	                      />
335	                    </Field>
336	                  );
337	                }}
338	              </form.Field>
339	
340	              <form.Field name="categoryLevel2">
341	                {(field) => {
342	                  const showError =
343	                    field.state.meta.isBlurred && !field.state.meta.isValid;
344	                  const level2Disabled =
345	                    disabled || level2Options.length === 0;
346	                  return (
347	                    <Field data-invalid={showError}>
348	                      <FieldLabel htmlFor={field.name}>中分類</FieldLabel>
349	                      <select
350	                        id={field.name}
351	                        name={field.name}
352	                        aria-invalid={showError}
353	                        value={field.state.value}
354	                        onChange={(event) => {
355	                          const next = event.target.value;
356	                          field.handleChange(next);
357	                          cascadeFromLevel2(level1Value, next);
358	                        }}
359	                        onBlur={field.handleBlur}
360	                        disabled={level2Disabled}
361	                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs disabled:opacity-50"
362	                      >
363	                        <option value="">
364	                          {level2Options.length === 0
365	                            ? "—"
366	                            : "選択してください"}
367	                        </option>
368	                        {level2Options.map((node) => (
369	                          <option key={node.slug} value={node.slug}>
370	                            {node.name}
371	                          </option>
372	                        ))}
373	                      </select>
374	                      <FieldError
375	                        errors={showError ? field.state.meta.errors : []}
376	                      />
377	                    </Field>
378	                  );
379	                }}
380	              </form.Field>
381	
382	              <form.Field name="categoryLevel3">
383	                {(field) => {
384	                  const showError =
385	                    field.state.meta.isBlurred && !field.state.meta.isValid;
386	                  const level3Disabled =
387	                    disabled || level3Options.length === 0;
388	                  return (
389	                    <Field data-invalid={showError}>
390	                      <FieldLabel htmlFor={field.name}>小分類</FieldLabel>
391	                      <select
392	                        id={field.name}
393	                        name={field.name}
394	                        aria-invalid={showError}
395	                        value={field.state.value}
396	                        onChange={(event) =>
397	                          field.handleChange(event.target.value)
398	                        }
399	                        onBlur={field.handleBlur}
400	                        disabled={level3Disabled}
401	                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs disabled:opacity-50"
402	                      >
403	                        <option value="">
404	                          {level3Options.length === 0
405	                            ? "—"
406	                            : "選択してください"}
407	                        </option>
408	                        {level3Options.map((node) => (
409	                          <option key={node.slug} value={node.slug}>
410	                            {node.name}
411	                          </option>
412	                        ))}
413	                      </select>
414	                      <FieldError
415	                        errors={showError ? field.state.meta.errors : []}
416	                      />
417	                    </Field>
418	                  );
419	                }}
420	              </form.Field>
421	            </div>
422	          </div>
423	        );
424	      }}
425	    </form.Subscribe>
426	  );
427	}
428	
429	function TagsField({
430	  form,
431	  disabled,
432	}: {
433	  form: Form;
434	  disabled: boolean;
435	}): JSX.Element {
436	  const [draft, setDraft] = useState("");
437	
438	  return (
439	    <form.Field name="tags" mode="array">
440	      {(tagsField) => {
441	        const tags = tagsField.state.value;
442	        const addTag = (): void => {
443	          const value = draft.trim();
444	          if (!value || tags.includes(value)) {
445	            setDraft("");
446	            return;
447	          }
448	          tagsField.pushValue(value);
449	          setDraft("");
450	        };
451	        // 配列フィールドは blur イベントを受けないため isTouched で判定する
452	        const showError =
453	          tagsField.state.meta.isTouched && !tagsField.state.meta.isValid;
454	        return (
455	          <Field data-invalid={showError}>
456	            <FieldLabel htmlFor="tags-input">
457	              タグ
458	              <RequiredOptionalBadge required={false} />
459	            </FieldLabel>
460	            <div className="flex flex-wrap gap-2">
461	              {tags.map((tag, index) => (
462	                <span
463	                  key={`${tag}-${index}`}
464	                  className="inline-flex items-center gap-1 rounded-full bg-secondary px-3 py-1 text-xs"
465	                >
466	                  {tag}
467	                  <button
468	                    type="button"
469	                    onClick={() => tagsField.removeValue(index)}
470	                    disabled={disabled}
471	                    className="text-muted-foreground hover:text-foreground"
472	                  >
473	                    <HugeiconsIcon icon={Cancel01Icon} className="size-3" />
474	                    <span className="sr-only">{tag} を削除</span>
475	                  </button>
476	                </span>
477	              ))}
478	            </div>
479	            <div className="flex gap-2">
480	              <Input
481	                id="tags-input"
482	                value={draft}
483	                onChange={(event) => setDraft(event.target.value)}
484	                onKeyDown={(event) => {
485	                  if (event.key === "Enter") {
486	                    event.preventDefault();
487	                    addTag();
488	                  }
489	                }}
490	                disabled={disabled}
491	              />
492	              <Button
493	                type="button"
494	                variant="outline"
495	                onClick={addTag}
496	                disabled={disabled}
497	              >
498	                追加
499	              </Button>
500	            </div>
501	            <FieldDescription>
502	              入力後 Enter または「追加」で追加。各 30 文字以内・最大 20 件
503	            </FieldDescription>
504	            <FieldError
505	              errors={showError ? tagsField.state.meta.errors : []}
506	            />
507	          </Field>
508	        );
509	      }}
510	    </form.Field>
511	  );
512	}
