import { expect, test } from "vitest";
import * as v from "valibot";
import {
  buildTopicBody,
  courseBasicFormSchema,
  courseSectionsFormSchema,
  toCourseBasicSubmissionPayload,
  toCourseSectionsSubmissionPayload,
} from "@/app/(main)/courses/new/_lib/course-form.schema";
import type { CategoryNode } from "@/app/(main)/courses/new/_lib/categories";

const sampleTree: CategoryNode[] = [
  {
    slug: "frontend",
    name: "Frontend",
    children: [
      {
        slug: "react",
        name: "React",
        children: [{ slug: "nextjs", name: "Next.js" }],
      },
    ],
  },
];

function buildValidBasic() {
  return {
    title: "Next.js 入門",
    description: "Next.js を学ぶコースです。",
    slug: "nextjs-basics",
    tags: ["nextjs", "react"],
    visibility: "public" as const,
    categoryLevel1: "frontend",
    categoryLevel2: "react",
    categoryLevel3: "nextjs",
  };
}

function buildValidSections() {
  return {
    sections: [
      {
        title: "はじめに",
        description: "セットアップ",
        topics: [
          {
            title: "インストール",
            description: "",
            goal: "Next.js を起動できる",
            knowledge: "Node.js が必要",
            steps: "### 1. インストール\nnpm install",
            completionCriteria: "npm run dev が成功する",
            supplement: "",
            comprehensionCheck: "",
          },
        ],
      },
    ],
  };
}

test("ステップ 1: 有効な値はそのままパースされる", () => {
  const result = v.safeParse(courseBasicFormSchema, buildValidBasic());
  expect(result.success).toBe(true);
});

test("ステップ 1: slug に大文字が含まれるとエラー", () => {
  const result = v.safeParse(courseBasicFormSchema, {
    ...buildValidBasic(),
    slug: "Nextjs-Basics",
  });
  expect(result.success).toBe(false);
});

test("ステップ 1: カテゴリ大分類が未選択だとエラー", () => {
  const result = v.safeParse(courseBasicFormSchema, {
    ...buildValidBasic(),
    categoryLevel1: "",
  });
  expect(result.success).toBe(false);
});

test("ステップ 1: カテゴリ中分類が未選択だとエラー", () => {
  const result = v.safeParse(courseBasicFormSchema, {
    ...buildValidBasic(),
    categoryLevel2: "",
  });
  expect(result.success).toBe(false);
});

test("ステップ 1: カテゴリ小分類が未選択だとエラー", () => {
  const result = v.safeParse(courseBasicFormSchema, {
    ...buildValidBasic(),
    categoryLevel3: "",
  });
  expect(result.success).toBe(false);
});

test("ステップ 2: 有効な値はそのままパースされる", () => {
  const result = v.safeParse(courseSectionsFormSchema, buildValidSections());
  expect(result.success).toBe(true);
});

test("ステップ 2: セクションが 0 件だとエラー", () => {
  const result = v.safeParse(courseSectionsFormSchema, { sections: [] });
  expect(result.success).toBe(false);
});

test("toCourseBasicSubmissionPayload はパスと表示名を導出する", () => {
  const payload = toCourseBasicSubmissionPayload(sampleTree, buildValidBasic());
  expect(payload.categoryPath).toBe("frontend.react.nextjs");
  expect(payload.categoryName).toBe("Next.js");
});

test("buildTopicBody は必須セクションのみのとき任意セクションを含めない", () => {
  const body = buildTopicBody({
    title: "インストール",
    description: "",
    goal: "Next.js を起動できる",
    knowledge: "Node.js が必要",
    steps: "### 1. インストール\nnpm install",
    completionCriteria: "npm run dev が成功する",
    supplement: "",
    comprehensionCheck: "",
  });

  expect(body).toBe(
    [
